usageExamples.code:
#include <type_traits>
#include <vector>
#include <iostream>

template<typename T, typename = void>
struct has_size : std::false_type {};

template<typename T>
struct has_size<T, std::void_t<decltype(std::declval<T>().size())>> : std::true_type {};

int main() {
    std::cout << has_size<std::vector<int>>::value; // 1 (true)
    std::cout << has_size<int>::value;               // 0 (false)
}

#include <type_traits>
#include <concepts>

// C++17: void_t + SFINAE — معقد
// template<typename T, typename = void>
// struct has_size : std::false_type {};
// template<typename T>
// struct has_size<T, std::void_t<decltype(std::declval<T>().size())>> : std::true_type {};

// C++20: concept — أنظم وأوضح
template<typename T>
concept HasSize = requires(T t) { t.size(); };

static_assert(HasSize<std::vector<int>>);
static_assert(!HasSize<int>);

