#include <type_traits>
#include <vector>
#include <iostream>

template<typename T>
void cleanup(T& item) {
    if constexpr (std::is_pointer_v<T>) {
        delete item;
        item = nullptr;
        std::cout << "deleted pointer\n";
    } else {
        std::cout << "not a pointer\n";
    }
}

int main() {
    int* p = new int(42);
    int x = 10;
    cleanup(p); // deleted pointer
    cleanup(x); // not a pointer
}

