#include <type_traits>
#include <iostream>

enum class Color : uint8_t { Red = 1, Green, Blue };

int main() {
    using UT = std::underlying_type_t<Color>;
    static_assert(std::is_same_v<UT, uint8_t>);
    Color c = Color::Green;
    UT val = static_cast<UT>(c);
    std::cout << static_cast<int>(val); // 2
}

