#include <type_traits>
#include <cmath>

template<typename T>
bool almost_equal(T a, T b) {
    if constexpr (std::is_floating_point_v<T>) {
        return std::fabs(a - b) < static_cast<T>(1e-6);
    } else {
        return a == b;
    }
}

